import * as cloneDeep from 'lodash.clonedeep';
import * as res from './resolvers';
import { OpenApiValidator, OpenApiValidatorOpts } from './openapi.validator';
import { OpenApiSpecLoader } from './framework/openapi.spec.loader';
import {
  InternalServerError,
  UnsupportedMediaType,
  RequestEntityTooLarge,
  BadRequest,
  MethodNotAllowed,
  NotAcceptable,
  NotFound,
  Unauthorized,
  Forbidden,
} from './framework/types';

// export default openapiValidator;
export const resolvers = res;
export const middleware = openapiValidator;
export const error = {
  InternalServerError,
  UnsupportedMediaType,
  RequestEntityTooLarge,
  BadRequest,
  MethodNotAllowed,
  NotAcceptable,
  NotFound,
  Unauthorized,
  Forbidden,
};

export * as serdes from './framework/base.serdes';

function openapiValidator(options: OpenApiValidatorOpts) {
  const oav = new OpenApiValidator(options);
  exports.middleware._oav = oav;

  return oav.installMiddleware(
    new OpenApiSpecLoader({
      apiDoc: cloneDeep(options.apiSpec),
      validateApiSpec: options.validateApiSpec,
      $refParser: options.$refParser,
    }).load(),
  );
}

import { Express as exExpress, NextFunction, Request } from "express";
import { Router as coreRouter } from "express-serve-static-core";
import { Server as httpServer } from "http";
import WebSocket = require("ws");

declare function expressWsRoutes(): expressWsRoutes.Express;

declare namespace expressWsRoutes {
    interface ClientInfo {
        origin: string;
        secure: boolean;
        req: Request;
    }
    type WebSocketHandler = (socket: WebSocket) => void;
    type CbHandler = (connectHandler: WebSocketHandler | boolean) => void;
    type WebSocketRouteHandler = (info: ClientInfo, cb: CbHandler, next: NextFunction) => void;

    interface Server extends httpServer {
        wsServer: WebSocket.Server;
    }

    interface Express extends exExpress {
        websocket(route: string, handler: WebSocketRouteHandler): Express;
    }

    interface Router extends coreRouter {
        websocket(route: string, handler: WebSocketRouteHandler): Router;
    }
}

export = expressWsRoutes;

import { ConnectionOptions } from "tls";

import { Handler } from "express";

declare function expressNtlm(options?: expressNtlm.Options): Handler;

declare namespace expressNtlm {
    interface Options {
        prefix?: string | undefined;
        badrequest?: Handler | undefined;
        internalservererror?: Handler | undefined;
        forbidden?: Handler | undefined;
        unauthorized?: Handler | undefined;
        domain?: string | undefined;
        domaincontroller?: string | readonly string[] | undefined;
        tlsOptions?: ConnectionOptions | undefined;
        debug?(prefix: string, message: string): void;
    }
    interface RequestNtlm {
        DomainName?: string | undefined;
        UserName?: string | undefined;
        Workstation?: string | undefined;
    }
}

declare global {
    namespace Express {
        interface Request {
            ntlm?: expressNtlm.RequestNtlm | undefined;
        }
    }
}

export = expressNtlm;

import socketio = require("socket.io");
import express = require("express");
import session = require("express-session");

declare module "socket.io" {
    interface Handshake {
        session?: session.Session & Partial<session.SessionData> | undefined;
        sessionID?: string | undefined;
    }
}

declare function sharedsession(
    expressSessionMiddleware: express.RequestHandler,
    cookieParserMiddleware: express.RequestHandler,
    options?: sharedsession.SharedSessionOptions,
): sharedsession.SocketIoSharedSessionMiddleware;

declare function sharedsession(
    expressSessionMiddleware: express.RequestHandler,
    options?: sharedsession.SharedSessionOptions,
): sharedsession.SocketIoSharedSessionMiddleware;

declare namespace sharedsession {
    interface SharedSessionOptions {
        autoSave?: boolean | undefined;
        saveUninitialized?: boolean | undefined;
    }

    type SocketIoSharedSessionMiddleware = (socket: socketio.Socket, next: (err?: any) => void) => void;
}

export = sharedsession;

import { Request } from "express";
import * as passport from "passport";
import { IBaseStrategyOption, ITokenPayload, VerifyCallback } from "./common";

export type VerifyBearerFunction = (token: ITokenPayload, done: VerifyCallback) => void;

export type VerifyBearerFunctionWithReq = (
    req: Request,
    token: ITokenPayload,
    done: VerifyCallback,
) => void;

export interface IBearerStrategyOption extends IBaseStrategyOption {
    audience?: string | string[] | undefined;
    policyName?: String | undefined;
    allowMultiAudiencesInToken?: boolean | undefined;
    scope?: string[] | undefined;
}

export interface IBearerStrategyOptionWithRequest extends IBearerStrategyOption {
    passReqToCallback: boolean;
}

export class BearerStrategy implements passport.Strategy {
    constructor(
        options: IBearerStrategyOptionWithRequest,
        verify: VerifyBearerFunctionWithReq,
    );
    constructor(options: IBearerStrategyOption, verify: VerifyBearerFunction);

    name: string;

    authenticate(req: Request, options?: object): void;
}
